external_knowledge:
- "gardeners" refers to customers;
- "cultivating both dreams and critiques" means having both a wishlist entry and a review for the same product;
- "the heart of the city that never sleeps, London" refers to customers whose address includes "London".

sql:
SELECT title, author, price
FROM products
WHERE product_quantity > 0 AND price > (
    SELECT AVG(price)
    FROM products
);

SELECT * 
FROM shipping 
WHERE shipping_id = 1;
